```javascript
const original = [1, 2, 3, 4, 5];

// Spread (shallow copy)
const copy1 = [...original];

// Array.from
const copy2 = Array.from(original);

// slice
const copy3 = original.slice();

// Non-mutating operations (return new arrays)
const added = [...original, 6];              // append
const removed = original.filter(x => x !== 3); // remove
const updated = original.map(x => x === 2 ? 20 : x); // replace
const inserted = [...original.slice(0, 2), 99, ...original.slice(2)];

// Deep copy (nested arrays/objects)
const deep = structuredClone(original);
```

All shallow copy methods share nested references. Use `structuredClone` for deep copies of nested structures.

ES6 introduced shorthand for object literals:

```javascript
const name = 'Alice';
const age = 30;

// Property shorthand
const user = { name, age };
// Equivalent to: { name: name, age: age }

// Method shorthand
const obj = {
  greet() { return 'hello'; },
  // Instead of: greet: function() { return 'hello'; }

  // Computed property names
  [dynamicKey]: 'value',
  [`get${name}`]: () => name
};

// Destructuring in parameters
function greet({ name, age = 0 }) {
  return `${name} is ${age}`;
}
greet({ name: 'Bob', age: 25 });
```

Shorthand reduces boilerplate and improves readability when variable names match property names.

```javascript
const arr = [1, 2, 2, 3, 3, 4];

// Using Set (simplest)
const unique = [...new Set(arr)]; // [1, 2, 3, 4]

// Using filter
const unique2 = arr.filter((v, i) => arr.indexOf(v) === i);

// For objects by key
const users = [
  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' },
  { id: 1, name: 'Alice' }
];

const uniqueUsers = [...new Map(users.map(u => [u.id, u])).values()];
// [{ id: 1, name: 'Alice' }, { id: 2, name: 'Bob' }]
```

`Set` is O(n) and handles primitives. For objects, use a `Map` keyed on the unique property.

```javascript
// Using Array.from
const range = (start, end) =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

range(1, 5);  // [1, 2, 3, 4, 5]
range(0, 9);  // [0, 1, 2, ..., 9]

// With step
const rangeStep = (start, end, step = 1) =>
  Array.from(
    { length: Math.ceil((end - start + 1) / step) },
    (_, i) => start + i * step
  );

rangeStep(0, 10, 2); // [0, 2, 4, 6, 8, 10]

// Generator (lazy, memory efficient)
function* rangeGen(start, end) {
  for (let i = start; i <= end; i++) yield i;
}
for (const n of rangeGen(1, 5)) console.log(n);
```

Use the Fisher-Yates (Knuth) shuffle for uniform randomness:

```javascript
function shuffle(arr) {
  const result = [...arr]; // don't mutate original
  for (let i = result.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [result[i], result[j]] = [result[j], result[i]];
  }
  return result;
}

shuffle([1, 2, 3, 4, 5]); // e.g., [3, 1, 5, 2, 4]
```

Do NOT use `.sort(() => Math.random() - 0.5)` — it produces biased results because sort comparators must be consistent. Fisher-Yates is O(n) time, O(1) extra space (or O(n) with the copy), and provides a truly uniform distribution.

```javascript
const items = [
  { type: 'fruit', name: 'apple' },
  { type: 'veggie', name: 'carrot' },
  { type: 'fruit', name: 'banana' },
  { type: 'veggie', name: 'pea' }
];

// Using reduce
function groupBy(arr, key) {
  return arr.reduce((groups, item) => {
    const group = item[key];
    (groups[group] ??= []).push(item);
    return groups;
  }, {});
}

// Using Object.groupBy (ES2024)
const grouped = Object.groupBy(items, item => item.type);

// Result:
// {
//   fruit: [{...apple}, {...banana}],
//   veggie: [{...carrot}, {...pea}]
// }
```

`Object.groupBy` is the modern standard approach. The `reduce` version works everywhere.

```javascript
class Pipeline {
  #value;
  constructor(value) { this.#value = value; }

  pipe(fn) {
    return new Pipeline(fn(this.#value));
  }

  get value() { return this.#value; }
}

const result = new Pipeline([1, 2, 3, 4, 5])
  .pipe(arr => arr.filter(n => n % 2 !== 0))
  .pipe(arr => arr.map(n => n * 10))
  .pipe(arr => arr.reduce((sum, n) => sum + n, 0))
  .value;
// 90

// Functional approach
const pipe = (...fns) => (input) =>
  fns.reduce((acc, fn) => fn(acc), input);

const process = pipe(
  arr => arr.filter(n => n > 2),
  arr => arr.map(n => n * 3)
);
process([1, 2, 3, 4]); // [9, 12]
```

Pipelines make sequential transformations readable. Each step is a pure function.

```javascript
// Object.entries: object -> [key, value] pairs
const obj = { a: 1, b: 2, c: 3 };
Object.entries(obj); // [['a', 1], ['b', 2], ['c', 3]]

// Useful for iteration
for (const [key, value] of Object.entries(obj)) {
  console.log(`${key}: ${value}`);
}

// Object.fromEntries: [key, value] pairs -> object
Object.fromEntries([['x', 10], ['y', 20]]); // { x: 10, y: 20 }

// Transform object values
const doubled = Object.fromEntries(
  Object.entries(obj).map(([k, v]) => [k, v * 2])
);
// { a: 2, b: 4, c: 6 }

// Map to object
const map = new Map([['name', 'Alice']]);
Object.fromEntries(map); // { name: 'Alice' }
```

Together they enable functional transformations on objects similar to array methods.

Tagged templates pass template literal parts to a function for custom processing:

```javascript
function highlight(strings, ...values) {
  return strings.reduce((result, str, i) => {
    const val = values[i] !== undefined ? `<mark>${values[i]}</mark>` : '';
    return result + str + val;
  }, '');
}

const name = 'Alice';
const age = 30;
highlight`Name: ${name}, Age: ${age}`;
// 'Name: <mark>Alice</mark>, Age: <mark>30</mark>'

// SQL safety
function sql(strings, ...values) {
  const text = strings.join('$' + strings.map((_, i) => i + 1).join('$'));
  return { text, values }; // parameterized query
}
```

The tag function receives an array of string segments and interpolated values separately. Used for HTML escaping, i18n, SQL parameterization, and CSS-in-JS (styled-components).

`structuredClone` performs a deep copy using the structured clone algorithm:

```javascript
const original = {
  date: new Date(),
  regex: /test/gi,
  set: new Set([1, 2]),
  map: new Map([['a', 1]]),
  buffer: new ArrayBuffer(8)
};

const clone = structuredClone(original);
// All types preserved correctly

// JSON round-trip loses types:
const jsonClone = JSON.parse(JSON.stringify(original));
// date -> string, regex -> {}, set -> {}, map -> {}
```

Key differences: `structuredClone` handles `Date`, `RegExp`, `Map`, `Set`, `ArrayBuffer`, `Blob`, circular references, and more. JSON cannot handle these, plus it drops `undefined`, functions, and `Symbol`. `structuredClone` cannot clone functions, DOM nodes, or Error objects.

```javascript
class LRUCache {
  #capacity;
  #cache = new Map();

  constructor(capacity) {
    this.#capacity = capacity;
  }

  get(key) {
    if (!this.#cache.has(key)) return undefined;
    const value = this.#cache.get(key);
    this.#cache.delete(key);
    this.#cache.set(key, value); // move to end (most recent)
    return value;
  }

  set(key, value) {
    if (this.#cache.has(key)) this.#cache.delete(key);
    else if (this.#cache.size >= this.#capacity) {
      const oldest = this.#cache.keys().next().value;
      this.#cache.delete(oldest);
    }
    this.#cache.set(key, value);
  }
}

const cache = new LRUCache(3);
cache.set('a', 1);
cache.set('b', 2);
cache.set('c', 3);
cache.get('a');     // 1 (moves 'a' to most recent)
cache.set('d', 4);  // evicts 'b' (least recently used)
```

Leverages `Map`'s insertion order. O(1) for both get and set.

`setTimeout` executes a callback once after a delay. `setInterval` executes repeatedly at a fixed interval.

```javascript
// Run once after 1 second
const timeoutId = setTimeout(() => console.log('once'), 1000);
clearTimeout(timeoutId); // cancel

// Run every 2 seconds
const intervalId = setInterval(() => console.log('tick'), 2000);
clearInterval(intervalId); // cancel

// setInterval can drift — recursive setTimeout is more accurate:
function preciseInterval(fn, delay) {
  function tick() {
    fn();
    setTimeout(tick, delay);
  }
  setTimeout(tick, delay);
}
```

`setInterval` does not account for execution time, so callbacks can overlap. Recursive `setTimeout` ensures the delay starts after the previous callback completes.

Return `this` from each method to enable chaining:

```javascript
class QueryBuilder {
  #table = '';
  #conditions = [];
  #limit = null;

  from(table) {
    this.#table = table;
    return this;
  }

  where(condition) {
    this.#conditions.push(condition);
    return this;
  }

  take(n) {
    this.#limit = n;
    return this;
  }

  build() {
    let sql = `SELECT * FROM ${this.#table}`;
    if (this.#conditions.length) {
      sql += ` WHERE ${this.#conditions.join(' AND ')}`;
    }
    if (this.#limit) sql += ` LIMIT ${this.#limit}`;
    return sql;
  }
}

new QueryBuilder()
  .from('users')
  .where('age > 18')
  .where('active = true')
  .take(10)
  .build();
```

The fluent interface pattern makes code read like natural language. Each method returns `this` to continue the chain.

```javascript
const obj = { name: 'Alice', age: 30, active: true };

Object.keys(obj);    // ['name', 'age', 'active']
Object.values(obj);  // ['Alice', 30, true]
Object.entries(obj); // [['name', 'Alice'], ['age', 30], ['active', true]]
```

All three return arrays of own enumerable string-keyed properties (not inherited, not Symbol-keyed). They share the same iteration order: integer keys first (ascending), then string keys in insertion order.

```javascript
// Common patterns
const hasValues = Object.values(obj).some(v => v === true);
const mapped = Object.fromEntries(
  Object.entries(obj).map(([k, v]) => [k, String(v)])
);
```

For Symbol keys, use `Object.getOwnPropertySymbols()`. For all properties including inherited, use `for...in`.

JavaScript uses automatic garbage collection, primarily with a mark-and-sweep algorithm:

1. The GC starts from roots (global object, call stack references)
2. It marks all objects reachable from roots
3. Unreachable objects are swept (freed)

```javascript
// Object becomes eligible for GC when unreachable
let obj = { data: 'large' };
obj = null; // original object can be collected

// Closure prevents collection
function createLeak() {
  const large = new Array(1000000);
  return () => large.length; // keeps 'large' alive
}

// Common memory leak patterns:
// 1. Forgotten timers: setInterval without clearInterval
// 2. Detached DOM nodes still referenced in JS
// 3. Closures capturing unnecessary variables
// 4. Growing arrays/maps without cleanup
```

Modern engines (V8) use generational GC — short-lived objects are collected more frequently than long-lived ones.

```javascript
function isEmpty(obj) {
  return Object.keys(obj).length === 0;
}

isEmpty({});          // true
isEmpty({ a: 1 });    // false

// For null/undefined safety
function isEmptySafe(obj) {
  return !obj || Object.keys(obj).length === 0;
}

// JSON approach (handles edge cases poorly)
JSON.stringify(obj) === '{}'; // works but slower
```

`Object.keys` only checks own enumerable properties. For objects with symbol keys, also check `Object.getOwnPropertySymbols(obj).length`.

Wrap the callback API in a `new Promise`:

```javascript
function readFileAsync(path) {
  return new Promise((resolve, reject) => {
    fs.readFile(path, 'utf8', (err, data) => {
      if (err) reject(err);
      else resolve(data);
    });
  });
}

// Usage
const content = await readFileAsync('file.txt');

// Node.js built-in utility
const { promisify } = require('util');
const readFile = promisify(fs.readFile);
const data = await readFile('file.txt', 'utf8');

// Node.js fs/promises (modern)
const { readFile } = require('fs/promises');
```

`util.promisify` automates this for Node.js-style callbacks (err-first pattern). Most modern APIs now provide Promise-based versions directly.

```javascript
class StateMachine {
  #state;
  #transitions;

  constructor(initialState, transitions) {
    this.#state = initialState;
    this.#transitions = transitions;
  }

  get state() { return this.#state; }

  send(event) {
    const key = `${this.#state}:${event}`;
    const next = this.#transitions[key];
    if (!next) throw new Error(`No transition: ${key}`);
    this.#state = next;
    return this.#state;
  }
}

const light = new StateMachine('red', {
  'red:NEXT': 'green',
  'green:NEXT': 'yellow',
  'yellow:NEXT': 'red'
});

light.send('NEXT'); // 'green'
light.send('NEXT'); // 'yellow'
light.send('NEXT'); // 'red'
```

State machines make complex state logic explicit and prevent invalid transitions. Useful for UI flows, game logic, and protocol handling.

```javascript
function titleCase(str) {
  return str.replace(/\b\w/g, char => char.toUpperCase());
}

titleCase('hello world');     // 'Hello World'
titleCase('the quick brown'); // 'The Quick Brown'

// Manual approach
function titleCaseManual(str) {
  return str
    .split(' ')
    .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
    .join(' ');
}

// Handle edge cases
function titleCaseSafe(str) {
  if (!str) return '';
  return str.toLowerCase().replace(/\b[a-z]/g, c => c.toUpperCase());
}
```

The regex `\b\w` matches word boundary followed by a word character. The manual split approach gives more control over lowercasing the rest.

An object is iterable if it has a `[Symbol.iterator]()` method that returns an iterator (object with a `next()` method):

```javascript
class Range {
  constructor(start, end) {
    this.start = start;
    this.end = end;
  }

  [Symbol.iterator]() {
    let current = this.start;
    const end = this.end;
    return {
      next() {
        if (current <= end) {
          return { value: current++, done: false };
        }
        return { done: true };
      }
    };
  }
}

const range = new Range(1, 5);
for (const n of range) console.log(n); // 1, 2, 3, 4, 5
[...range]; // [1, 2, 3, 4, 5]
```

Iterables work with `for...of`, spread, destructuring, `Array.from`, `Promise.all`, and other built-in consumers.

Function declarations are fully hoisted — both the name and body are available before the declaration:

```javascript
// Works: declaration is hoisted
console.log(add(2, 3)); // 5
function add(a, b) { return a + b; }

// Fails: only variable is hoisted, not the function
console.log(multiply(2, 3)); // TypeError: multiply is not a function
var multiply = function(a, b) { return a * b; };

// Also fails with arrow functions
console.log(divide(6, 2)); // ReferenceError
const divide = (a, b) => a / b;
```

With `var`, the variable is hoisted as `undefined`. With `let`/`const`, accessing before declaration throws a `ReferenceError` (TDZ). Only function declarations are fully hoisted.

```javascript
class TreeNode {
  constructor(value, left = null, right = null) {
    this.value = value;
    this.left = left;
    this.right = right;
  }
}

function inorder(node, result = []) {
  if (!node) return result;
  inorder(node.left, result);
  result.push(node.value);
  inorder(node.right, result);
  return result;
}

function preorder(node, result = []) {
  if (!node) return result;
  result.push(node.value);
  preorder(node.left, result);
  preorder(node.right, result);
  return result;
}

function postorder(node, result = []) {
  if (!node) return result;
  postorder(node.left, result);
  postorder(node.right, result);
  result.push(node.value);
  return result;
}
```

Inorder (left, root, right) gives sorted order for BSTs. Preorder (root, left, right) is used for serialization. Postorder (left, right, root) for deletion.

```javascript
const user = { profile: { address: { city: 'NYC' } } };

// Optional chaining (modern)
const city = user?.profile?.address?.city; // 'NYC'
const zip = user?.profile?.address?.zip;   // undefined

// With nullish coalescing for defaults
const country = user?.profile?.address?.country ?? 'US';

// Legacy: lodash-style get function
function get(obj, path, defaultVal = undefined) {
  const keys = path.split('.');
  let result = obj;
  for (const key of keys) {
    result = result?.[key];
    if (result === undefined) return defaultVal;
  }
  return result;
}

get(user, 'profile.address.city'); // 'NYC'
get(user, 'profile.phone', 'N/A'); // 'N/A'
```

Optional chaining (`?.`) is the modern standard. The utility function is useful when paths are dynamic strings.

```typescript
type Listener<T> = (data: T) => void;

class TypedEventEmitter<Events extends Record<string, any>> {
  private listeners = new Map<keyof Events, Set<Function>>();

  on<K extends keyof Events>(event: K, listener: Listener<Events[K]>): () => void {
    if (!this.listeners.has(event)) this.listeners.set(event, new Set());
    this.listeners.get(event)!.add(listener);
    return () => this.listeners.get(event)!.delete(listener);
  }

  emit<K extends keyof Events>(event: K, data: Events[K]): void {
    this.listeners.get(event)?.forEach(fn => fn(data));
  }
}

// Usage — fully typed events
interface AppEvents {
  'user:login': { userId: string };
  'item:added': { itemId: number; name: string };
}

const bus = new TypedEventEmitter<AppEvents>();
bus.on('user:login', ({ userId }) => console.log(userId));
bus.emit('user:login', { userId: 'abc' });
```

```javascript
const users = [
  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' },
  { id: 3, name: 'Charlie' }
];

// find: returns the first matching ELEMENT (or undefined)
const bob = users.find(u => u.name === 'Bob');
// { id: 2, name: 'Bob' }

// findIndex: returns the first matching INDEX (or -1)
const bobIndex = users.findIndex(u => u.name === 'Bob');
// 1

// findLast / findLastIndex (ES2023): search from the end
const last = [1, 2, 3, 2].findLast(x => x === 2);      // 2 (last one)
const lastIdx = [1, 2, 3, 2].findLastIndex(x => x === 2); // 3
```

Use `find` when you need the value, `findIndex` when you need the position (e.g., for splice or slice). Both stop at the first match — O(n) worst case.

Use `async/await` for sequential dependent operations:

```javascript
async function processOrder(orderId) {
  // Sequential — each step depends on the previous
  const order = await fetchOrder(orderId);
  const user = await fetchUser(order.userId);
  const address = await fetchAddress(user.addressId);

  // Independent operations can run in parallel
  const [inventory, pricing] = await Promise.all([
    checkInventory(order.items),
    calculatePricing(order.items, user.tier)
  ]);

  return { order, user, address, inventory, pricing };
}
```

Pattern: use sequential `await` for dependent calls, `Promise.all` for independent ones. This minimizes total wait time while respecting data dependencies.

`let` creates a new binding per loop iteration, so each closure captures its own copy:

```javascript
// var: shared binding
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 10);
}
// Output: 3, 3, 3 (all see final i)

// let: per-iteration binding
for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 10);
}
// Output: 0, 1, 2 (each sees its own i)

// forEach also creates a new scope per iteration
[0, 1, 2].forEach(i => {
  setTimeout(() => console.log(i), 10);
});
// Output: 0, 1, 2
```

This is because `let` in a `for` loop is spec'd to create a fresh lexical environment for each iteration.

Use a Result wrapper that short-circuits on error:

```javascript
class Result {
  #value;
  #error;

  constructor(value, error = null) {
    this.#value = value;
    this.#error = error;
  }

  static ok(value) { return new Result(value); }
  static err(error) { return new Result(null, error); }

  map(fn) {
    if (this.#error) return this;
    try { return Result.ok(fn(this.#value)); }
    catch (e) { return Result.err(e); }
  }

  unwrap() {
    if (this.#error) throw this.#error;
    return this.#value;
  }
}

const result = Result.ok('{"name": "Alice"}')
  .map(JSON.parse)
  .map(obj => obj.name.toUpperCase())
  .map(name => `Hello, ${name}`);

result.unwrap(); // 'Hello, ALICE'
```

Inspired by Rust's `Result` type. Once an error occurs, subsequent `.map()` calls are skipped.

A shallow copy duplicates top-level properties but shares nested references. A deep copy recursively clones all levels.

```javascript
const original = { a: 1, nested: { b: 2 } };

// Shallow copy — nested objects are shared
const shallow = { ...original };
shallow.a = 10;         // doesn't affect original
shallow.nested.b = 20;  // AFFECTS original!

// Deep copy — fully independent
const deep = structuredClone(original);
deep.nested.b = 30;     // doesn't affect original

console.log(original.nested.b); // 20 (shallow mutated it)
```

Shallow copy methods: spread `{...}`, `Object.assign`, `Array.slice`. Deep copy methods: `structuredClone` (modern), `JSON.parse(JSON.stringify())` (lossy), or recursive cloning. Use deep copy when nested mutation must be independent.

```javascript
const items = ['apple', 'banana', 'apple', 'cherry', 'banana', 'apple'];

// Count occurrences
const counts = items.reduce((acc, item) => {
  acc[item] = (acc[item] || 0) + 1;
  return acc;
}, {});
// { apple: 3, banana: 2, cherry: 1 }

// Build a lookup map
const users = [{ id: 1, name: 'A' }, { id: 2, name: 'B' }];
const byId = users.reduce((map, u) => ({ ...map, [u.id]: u }), {});

// Flatten array of arrays
const nested = [[1, 2], [3, 4], [5]];
const flat = nested.reduce((acc, arr) => acc.concat(arr), []);
// [1, 2, 3, 4, 5]

// Pipeline of functions
const fns = [x => x + 1, x => x * 2, x => x - 3];
const result = fns.reduce((val, fn) => fn(val), 5);
// ((5 + 1) * 2) - 3 = 9
```

