Use closures to create private state:

```javascript
function createPerson(name, age) {
  // Private variables — not accessible from outside
  let _name = name;
  let _age = age;

  return {
    getName() { return _name; },
    getAge() { return _age; },
    setName(n) {
      if (typeof n !== 'string') throw new TypeError('Name must be string');
      _name = n;
