// Add and delete
set.add(4);       // {1, 2, 3, 4}
set.delete(2);    // {1, 3, 4}
set.has(3);       // true
set.size;         // 3
set.clear();      // empty set

// Iteration
for (const val of set) console.log(val);
set.forEach(val => console.log(val));

