```javascript
const arr = [1, 2, 3, 4, 5];

// for...of: supports break, continue, return
for (const val of arr) {
  if (val === 3) break; // stops iteration
  console.log(val);     // 1, 2
}

// forEach: no break, no continue, no return (from outer)
arr.forEach(val => {
  if (val === 3) return; // only skips current callback
  console.log(val);      // 1, 2, 4, 5
});

// for...of works with any iterable
for (const char of 'hello') console.log(char);
for (const [k, v] of map) console.log(k, v);

// forEach is array-only (and NodeList)
// Cannot use await inside forEach effectively
