Prefer `for...of` when you need `break`/`continue`, `await`, or work with non-array iterables. Use `forEach` for simple callbacks where you process every element.

```javascript
class Router {
  #routes = new Map();

  route(path, handler) {
    this.#routes.set(path, handler);
    return this;
  }

  navigate(path) {
    window.history.pushState({}, '', path);
    this.#resolve(path);
  }

  #resolve(path) {
    const handler = this.#routes.get(path);
    if (handler) handler();
    else console.warn(`No route for ${path}`);
  }

  start() {
    window.addEventListener('popstate', () => {
      this.#resolve(window.location.pathname);
    });
    this.#resolve(window.location.pathname);
  }
}

const router = new Router();
router
  .route('/', () => render('Home'))
  .route('/about', () => render('About'))
  .start();
```

Uses the History API for clean URLs. `pushState` changes the URL without reloading. `popstate` fires on back/forward navigation.

`Symbol.toPrimitive` customizes how an object is converted to a primitive value:

```javascript
class Money {
  constructor(amount, currency) {
    this.amount = amount;
    this.currency = currency;
  }

  [Symbol.toPrimitive](hint) {
    switch (hint) {
      case 'number':  return this.amount;
      case 'string':  return `${this.amount} ${this.currency}`;
      case 'default': return this.amount;
    }
  }
}

const price = new Money(42.5, 'USD');

+price;            // 42.5  (hint: 'number')
`${price}`;        // '42.5 USD' (hint: 'string')
price + 10;        // 52.5  (hint: 'default')
price > 40;        // true  (hint: 'number')
```

The `hint` parameter is `'number'`, `'string'`, or `'default'`. Without this method, JavaScript falls back to `valueOf()` and `toString()`.

```javascript
function bisectLeft(arr, target) {
  let lo = 0, hi = arr.length;
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (arr[mid] < target) lo = mid + 1;
    else hi = mid;
  }
  return lo;
}

function bisectRight(arr, target) {
  let lo = 0, hi = arr.length;
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (arr[mid] <= target) lo = mid + 1;
    else hi = mid;
  }
  return lo;
}

const arr = [1, 3, 5, 5, 5, 7, 9];
bisectLeft(arr, 5);  // 2 (first 5)
bisectRight(arr, 5); // 5 (after last 5)

// Insert maintaining sorted order
function sortedInsert(arr, val) {
  const idx = bisectLeft(arr, val);
  arr.splice(idx, 0, val);
}
```

`bisectLeft` finds the leftmost insertion point, `bisectRight` the rightmost. Both are O(log n).

```javascript
const a = { x: 1 };
const b = { y: 2 };

// Both create shallow copies / merges
const spread = { ...a, ...b };          // { x: 1, y: 2 }
const assigned = Object.assign({}, a, b); // { x: 1, y: 2 }

// Key differences:

// 1. Object.assign mutates the first argument
Object.assign(a, b); // a is now { x: 1, y: 2 }

// 2. Object.assign invokes setters on target
const target = { set x(v) { console.log('set!', v); } };
Object.assign(target, { x: 1 }); // triggers setter
const spread2 = { ...target, x: 1 }; // does NOT trigger setter

// 3. Spread only copies own enumerable properties
// Both ignore inherited properties
```

Prefer spread (`{...}`) for creating new objects immutably. Use `Object.assign` when you intentionally want to mutate the target or need setter invocation.

```javascript
function truncate(str, maxLength, suffix = '...') {
  if (str.length <= maxLength) return str;
  return str.slice(0, maxLength - suffix.length) + suffix;
}

truncate('Hello, World!', 10);    // 'Hello, ...' 
truncate('Short', 10);             // 'Short'
truncate('Hello, World!', 10, '~'); // 'Hello, Wo~'

// Word-boundary aware
function truncateWords(str, maxLength, suffix = '...') {
  if (str.length <= maxLength) return str;
  const trimmed = str.slice(0, maxLength - suffix.length);
  const lastSpace = trimmed.lastIndexOf(' ');
  return (lastSpace > 0 ? trimmed.slice(0, lastSpace) : trimmed) + suffix;
}

truncateWords('The quick brown fox', 15); // 'The quick...'
```

The word-boundary version avoids cutting words in half, which reads more naturally.

```javascript
async function promisePool(tasks, concurrency) {
  const results = [];
  const executing = new Set();

  for (const [index, task] of tasks.entries()) {
    const promise = task().then(result => {
      executing.delete(promise);
      results[index] = result;
    });
    executing.add(promise);

    if (executing.size >= concurrency) {
      await Promise.race(executing);
    }
  }

  await Promise.all(executing);
  return results;
}

// Usage: fetch 100 URLs, 5 at a time
const tasks = urls.map(url => () => fetch(url).then(r => r.json()));
const results = await promisePool(tasks, 5);
```

The pool launches new tasks as previous ones complete, maintaining at most `concurrency` in-flight promises. Results are ordered by input index, not completion order.
